def validate(args, output):
    k = args[0]
    rowConditions = args[1]
    colConditions = args[2]
    def feasible(conds):
        from collections import defaultdict, deque
        adj = defaultdict(set)
        for a, b in conds:
            adj[a].add(b)
        indeg = {i: 0 for i in range(1, k + 1)}
        for a in adj:
            for b in adj[a]:
                indeg[b] += 1
        q = deque([i for i in range(1, k + 1) if indeg[i] == 0])
        cnt = 0
        while q:
            u = q.popleft()
            cnt += 1
            for v in adj[u]:
                indeg[v] -= 1
                if indeg[v] == 0:
                    q.append(v)
        return cnt == k
    possible = feasible(rowConditions) and feasible(colConditions)
    if not isinstance(output, list):
        return False
    if not possible:
        return output == []
    # structural: k x k, each 1..k exactly once, rest 0
    if len(output) != k:
        return False
    row_of = {}
    col_of = {}
    seen = set()
    for r, row in enumerate(output):
        if not isinstance(row, list) or len(row) != k:
            return False
        for c, val in enumerate(row):
            if val == 0:
                continue
            if not isinstance(val, int) or val < 1 or val > k or val in seen:
                return False
            seen.add(val)
            row_of[val] = r
            col_of[val] = c
    if len(seen) != k:
        return False
    for a, b in rowConditions:
        if not (row_of[a] < row_of[b]):
            return False
    for a, b in colConditions:
        if not (col_of[a] < col_of[b]):
            return False
    return True

