function validate(args, output) {
    const k = args[0];
    const rowConditions = args[1];
    const colConditions = args[2];
    const feasible = (conds) => {
        const adj = new Map();
        const indeg = new Map();
        for (let i = 1; i <= k; i++) { adj.set(i, new Set()); indeg.set(i, 0); }
        for (const [a, b] of conds) {
            if (!adj.get(a).has(b)) { adj.get(a).add(b); indeg.set(b, indeg.get(b) + 1); }
        }
        const q = [];
        for (let i = 1; i <= k; i++) if (indeg.get(i) === 0) q.push(i);
        let cnt = 0;
        while (q.length) {
            const u = q.shift();
            cnt++;
            for (const v of adj.get(u)) {
                indeg.set(v, indeg.get(v) - 1);
                if (indeg.get(v) === 0) q.push(v);
            }
        }
        return cnt === k;
    };
    const possible = feasible(rowConditions) && feasible(colConditions);
    if (!Array.isArray(output)) return false;
    if (!possible) return output.length === 0;
    if (output.length !== k) return false;
    const rowOf = {}, colOf = {};
    const seen = new Set();
    for (let r = 0; r < k; r++) {
        const row = output[r];
        if (!Array.isArray(row) || row.length !== k) return false;
        for (let c = 0; c < k; c++) {
            const val = row[c];
            if (val === 0) continue;
            if (!Number.isInteger(val) || val < 1 || val > k || seen.has(val)) return false;
            seen.add(val);
            rowOf[val] = r;
            colOf[val] = c;
        }
    }
    if (seen.size !== k) return false;
    for (const [a, b] of rowConditions) if (!(rowOf[a] < rowOf[b])) return false;
    for (const [a, b] of colConditions) if (!(colOf[a] < colOf[b])) return false;
    return true;
}

