def gen(rng, size):
    k = max(2, min(size, 12))
    def make_conds():
        perm = list(range(1, k + 1))
        rng.shuffle(perm)
        pos = {v: i for i, v in enumerate(perm)}
        conds = []
        for _ in range(rng.randint(1, 2 * k)):
            a = rng.randint(1, k)
            b = rng.randint(1, k)
            if pos[a] < pos[b]:
                conds.append([a, b])
            elif pos[b] < pos[a]:
                conds.append([b, a])
        if not conds:
            conds.append([perm[0], perm[1]])
        return conds
    return [k, make_conds(), make_conds()]

