class Solution:
    def buildMatrix(self, k, rowConditions, colConditions):
        def topo(conds):
            import heapq
            from collections import defaultdict
            adj = defaultdict(set)
            for a, b in conds:
                adj[a].add(b)
            indeg = {i: 0 for i in range(1, k + 1)}
            for a in adj:
                for b in adj[a]:
                    indeg[b] += 1
            heap = [i for i in range(1, k + 1) if indeg[i] == 0]
            heapq.heapify(heap)
            order = []
            while heap:
                u = heapq.heappop(heap)
                order.append(u)
                for v in sorted(adj[u]):
                    indeg[v] -= 1
                    if indeg[v] == 0:
                        heapq.heappush(heap, v)
            return order if len(order) == k else None
        ro = topo(rowConditions)
        co = topo(colConditions)
        if ro is None or co is None:
            return []
        rrank = {v: i for i, v in enumerate(ro)}
        crank = {v: i for i, v in enumerate(co)}
        mat = [[0] * k for _ in range(k)]
        for v in range(1, k + 1):
            mat[rrank[v]][crank[v]] = v
        return mat

