var buildMatrix = function(k, rowConditions, colConditions) {
    const topo = (conds) => {
        const adj = new Map();
        const indeg = new Map();
        for (let i = 1; i <= k; i++) { adj.set(i, new Set()); indeg.set(i, 0); }
        for (const [a, b] of conds) {
            if (!adj.get(a).has(b)) { adj.get(a).add(b); indeg.set(b, indeg.get(b) + 1); }
        }
        const avail = [];
        for (let i = 1; i <= k; i++) if (indeg.get(i) === 0) avail.push(i);
        const order = [];
        while (avail.length) {
            avail.sort((a, b) => a - b);
            const u = avail.shift();
            order.push(u);
            const nbrs = [...adj.get(u)].sort((a, b) => a - b);
            for (const v of nbrs) {
                indeg.set(v, indeg.get(v) - 1);
                if (indeg.get(v) === 0) avail.push(v);
            }
        }
        return order.length === k ? order : null;
    };
    const ro = topo(rowConditions);
    const co = topo(colConditions);
    if (ro === null || co === null) return [];
    const rrank = {}, crank = {};
    ro.forEach((v, i) => rrank[v] = i);
    co.forEach((v, i) => crank[v] = i);
    const mat = Array.from({length: k}, () => new Array(k).fill(0));
    for (let v = 1; v <= k; v++) mat[rrank[v]][crank[v]] = v;
    return mat;
};
